    /**
     * JSON-LD @type to match (e.g., "Article", "Product")
     */
    type?: string;
    /**
     * Dot-separated path in JSON-LD object (e.g., "author.name")
     */
    path?: string;
    /**
     * Whether to extract all matches
     */
